// antispam basico: descartar si falta nombre/contacto o parece bot
const b=$json.body||$json;
if(!b.nombre||!b.contacto||b.nombre.length>80||/https?:\/\//i.test(b.nombre)){return [];}
return [{json:{actividad:b.actividad,nombre:b.nombre.trim(),contacto:b.contacto.trim(),idioma:b.idioma||'es',fecha:new Date().toISOString()}}];
